const CopyButton = ({ text }) => {
  const [isCopied, setIsCopied] = useState(false);

  const handleCopy = async () => {
    try {
      await navigator.clipboard.writeText(text);
      setIsCopied(true);
      setTimeout(() => setIsCopied(false), 1500);
    } catch (err) {
      console.error('Failed to copy: ', err);
    }
  };

  return (
    <>
      <button
        onClick={handleCopy}
        disabled={isCopied}
        className="flex items-center justify-center px-3 py-1.5 bg-blue-500 text-white rounded-md hover:bg-blue-600 disabled:bg-green-500 disabled:cursor-not-allowed transition-colors"
        aria-label={isCopied ? 'Copied' : 'Copy to clipboard'}
      >
        {isCopied ? <CheckIcon /> : <CopyIcon />}
      </button>
      <div aria-live="polite" className="sr-only">
        {isCopied && 'Text copied to clipboard'}
      </div>
    </>
  );
};

export default CopyButton;
